class MinHeap {
    constructor() {
        this.heap = [];
    }
    push(cost, i, j) {
        this.heap.push([cost, i, j]);
        this.bubbleUp(this.heap.length - 1);
    }
    bubbleUp(idx) {
        while (idx > 0) {
            const parentIdx = Math.floor((idx - 1) / 2);
            if (this.heap[parentIdx][0] <= this.heap[idx][0]) break;
            [this.heap[parentIdx], this.heap[idx]] = [this.heap[idx], this.heap[parentIdx]];
            idx = parentIdx;
        }
    }
    pop() {
        if (this.heap.length === 0) return null;
        const min = this.heap[0];
        const last = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = last;
            this.sinkDown(0);
        }
        return min;
    }
    sinkDown(idx) {
        const length = this.heap.length;
        while (true) {
            const left = 2 * idx + 1;
            const right = 2 * idx + 2;
            let smallest = idx;
            if (left < length && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right < length && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }
            if (smallest === idx) break;
            [this.heap[idx], this.heap[smallest]] = [this.heap[smallest], this.heap[idx]];
            idx = smallest;
        }
    }
    isEmpty() {
        return this.heap.length === 0;
    }
}

function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const INF = Number.MAX_SAFE_INTEGER;
    let maxVal = 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] > maxVal) {
                maxVal = grid[i][j];
            }
        }
    }

    const dp = new Array(m);
    for (let i = 0; i < m; i++) {
        dp[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dp[i][j] = new Array(k + 1).fill(INF);
        }
    }
    dp[0][0][0] = 0;

    for (let tele = 0; tele <= k; tele++) {
        const heap = new MinHeap();
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (dp[i][j][tele] < INF) {
                    heap.push(dp[i][j][tele], i, j);
                }
            }
        }

        while (!heap.isEmpty()) {
            const [cost, i, j] = heap.pop();
            if (cost !== dp[i][j][tele]) continue;

            const moves = [[0, 1], [1, 0]];
            for (const [dx, dy] of moves) {
                const ni = i + dx;
                const nj = j + dy;
                if (ni < m && nj < n) {
                    const newCost = cost + grid[ni][nj];
                    if (newCost < dp[ni][nj][tele]) {
                        dp[ni][nj][tele] = newCost;
                        heap.push(newCost, ni, nj);
                    }
                }
            }
        }

        if (tele < k) {
            const base = new Array(maxVal + 1).fill(INF);
            for (let i = 0; i < m; i++) {
                for (let j = 0; j < n; j++) {
                    const val = grid[i][j];
                    if (dp[i][j][tele] < base[val]) {
                        base[val] = dp[i][j][tele];
                    }
                }
            }
            for (let v = maxVal - 1; v >= 0; v--) {
                base[v] = Math.min(base[v], base[v + 1]);
            }
            for (let i = 0; i < m; i++) {
                for (let j = 0; j < n; j++) {
                    const w = grid[i][j];
                    if (base[w] < dp[i][j][tele + 1]) {
                        dp[i][j][tele + 1] = base[w];
                    }
                }
            }
        }
    }

    let ans = INF;
    for (let t = 0; t <= k; t++) {
        ans = Math.min(ans, dp[m - 1][n - 1][t]);
    }
    return ans;
}
